/**
 * 🔗 Share Link Service
 *
 * Serviço para criação e validação de links compartilháveis
 * com token seguro e expiração configurável.
 */

import crypto from 'crypto';
import { prisma } from '@lib/prisma';
import { Logger } from '@lib/logger';

const logger = new Logger('share-link-service');

// =============================================================================
// Types
// =============================================================================

export interface CreateShareLinkInput {
  projectId: string;
  userId: string;
  resourceType?: 'video' | 'project' | 'export';
  resourceId?: string;
  /** Expiração em horas (default: 72h) */
  expirationHours?: number;
  /** Número máximo de visualizações (null = ilimitado) */
  maxViews?: number;
  /** Senha opcional para proteção extra */
  password?: string;
}

export interface ShareLinkResult {
  id: string;
  token: string;
  url: string;
  expiresAt: Date;
  maxViews: number | null;
  isActive: boolean;
}

export interface ResolvedShareLink {
  projectId: string;
  userId: string;
  resourceType: string;
  resourceId: string | null;
  metadata: Record<string, unknown>;
  project: {
    id: string;
    name: string;
    thumbnailUrl: string | null;
    previewUrl: string | null;
  } | null;
  renderJob: {
    id: string;
    outputUrl: string | null;
    status: string | null;
  } | null;
}

// =============================================================================
// Service
// =============================================================================

/**
 * Gera um token seguro de 32 bytes (64 chars hex)
 */
function generateToken(): string {
  return crypto.randomBytes(32).toString('hex');
}

/**
 * Hash bcrypt-like simples para senha de share link.
 * Usa HMAC com secret do ambiente para segurança.
 */
function hashPassword(password: string): string {
  const secret = process.env.SHARE_LINK_SECRET || process.env.NEXTAUTH_SECRET || 'share-link-default-secret';
  return crypto.createHmac('sha256', secret).update(password).digest('hex');
}

/**
 * Verifica se a senha fornecida corresponde ao hash armazenado.
 */
function verifyPassword(password: string, hash: string): boolean {
  const computed = hashPassword(password);
  return crypto.timingSafeEqual(Buffer.from(computed), Buffer.from(hash));
}

/**
 * Cria um link compartilhável para um projeto/vídeo.
 */
export async function createShareLink(input: CreateShareLinkInput): Promise<ShareLinkResult> {
  const {
    projectId,
    userId,
    resourceType = 'video',
    resourceId,
    expirationHours = 72,
    maxViews,
    password,
  } = input;

  logger.info('Creating share link', { projectId, userId, resourceType, expirationHours });

  // Verificar que o projeto pertence ao usuário
  const project = await prisma.projects.findFirst({
    where: { id: projectId, userId },
    select: { id: true },
  });

  if (!project) {
    throw new ShareLinkError('Projeto não encontrado ou sem permissão', 'PROJECT_NOT_FOUND');
  }

  const token = generateToken();
  const expiresAt = new Date(Date.now() + expirationHours * 60 * 60 * 1000);
  const hashedPassword = password ? hashPassword(password) : null;

  const shareLink = await prisma.share_links.create({
    data: {
      token,
      projectId,
      userId,
      resourceType,
      resourceId: resourceId || null,
      expiresAt,
      maxViews: maxViews ?? null,
      password: hashedPassword,
      metadata: {},
    },
  });

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL || process.env.NEXTAUTH_URL || 'http://localhost:3000';
  const url = `${baseUrl}/share/${token}`;

  logger.info('Share link created', { id: shareLink.id, token: token.slice(0, 8) + '...', expiresAt: expiresAt.toISOString() });

  return {
    id: shareLink.id,
    token,
    url,
    expiresAt,
    maxViews: maxViews ?? null,
    isActive: true,
  };
}

/**
 * Resolve um link compartilhável pelo token.
 * Verifica expiração, limite de views, e status ativo.
 */
export async function resolveShareLink(token: string, password?: string): Promise<ResolvedShareLink> {
  logger.info('Resolving share link', { token: token.slice(0, 8) + '...' });

  const shareLink = await prisma.share_links.findUnique({
    where: { token },
  });

  if (!shareLink) {
    throw new ShareLinkError('Link não encontrado', 'LINK_NOT_FOUND');
  }

  // Verificar se está ativo
  if (!shareLink.isActive) {
    throw new ShareLinkError('Link desativado', 'LINK_DISABLED');
  }

  // Verificar expiração
  if (new Date() > shareLink.expiresAt) {
    // Desativar automaticamente
    await prisma.share_links.update({
      where: { id: shareLink.id },
      data: { isActive: false },
    });
    throw new ShareLinkError('Link expirado', 'LINK_EXPIRED');
  }

  // Verificar limite de views
  if (shareLink.maxViews !== null && shareLink.viewCount >= shareLink.maxViews) {
    await prisma.share_links.update({
      where: { id: shareLink.id },
      data: { isActive: false },
    });
    throw new ShareLinkError('Limite de visualizações atingido', 'MAX_VIEWS_REACHED');
  }

  // Verificar senha se definida
  if (shareLink.password) {
    if (!password) {
      throw new ShareLinkError('Senha obrigatória', 'PASSWORD_REQUIRED');
    }
    if (!verifyPassword(password, shareLink.password)) {
      throw new ShareLinkError('Senha incorreta', 'INVALID_PASSWORD');
    }
  }

  // Incrementar view count
  await prisma.share_links.update({
    where: { id: shareLink.id },
    data: { viewCount: { increment: 1 } },
  });

  // Buscar dados do projeto
  const project = await prisma.projects.findUnique({
    where: { id: shareLink.projectId },
    select: {
      id: true,
      name: true,
      thumbnailUrl: true,
      previewUrl: true,
    },
  });

  // Buscar render job mais recente do projeto (se resourceType for video)
  let renderJob: ResolvedShareLink['renderJob'] = null;
  if (shareLink.resourceType === 'video' || shareLink.resourceType === 'export') {
    const job = await prisma.render_jobs.findFirst({
      where: {
        projectId: shareLink.projectId,
        status: 'completed',
      },
      orderBy: { completedAt: 'desc' },
      select: {
        id: true,
        outputUrl: true,
        status: true,
      },
    });
    if (job) {
      renderJob = {
        id: job.id,
        outputUrl: job.outputUrl,
        status: job.status,
      };
    }
  }

  logger.info('Share link resolved', {
    id: shareLink.id,
    viewCount: shareLink.viewCount + 1,
    projectId: shareLink.projectId,
  });

  return {
    projectId: shareLink.projectId,
    userId: shareLink.userId,
    resourceType: shareLink.resourceType,
    resourceId: shareLink.resourceId,
    metadata: (shareLink.metadata as Record<string, unknown>) || {},
    project,
    renderJob,
  };
}

/**
 * Lista links compartilhados de um usuário para um projeto.
 */
export async function listShareLinks(
  userId: string,
  projectId?: string,
): Promise<ShareLinkResult[]> {
  const where: Record<string, unknown> = { userId };
  if (projectId) {
    where.projectId = projectId;
  }

  const links = await prisma.share_links.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    take: 50,
  });

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL || process.env.NEXTAUTH_URL || 'http://localhost:3000';

  return links.map((link) => ({
    id: link.id,
    token: link.token,
    url: `${baseUrl}/share/${link.token}`,
    expiresAt: link.expiresAt,
    maxViews: link.maxViews,
    isActive: link.isActive && new Date() < link.expiresAt,
  }));
}

/**
 * Revoga (desativa) um link compartilhável.
 */
export async function revokeShareLink(linkId: string, userId: string): Promise<void> {
  const link = await prisma.share_links.findFirst({
    where: { id: linkId, userId },
  });

  if (!link) {
    throw new ShareLinkError('Link não encontrado', 'LINK_NOT_FOUND');
  }

  await prisma.share_links.update({
    where: { id: linkId },
    data: { isActive: false },
  });

  logger.info('Share link revoked', { id: linkId, userId });
}

// =============================================================================
// Error class
// =============================================================================

export type ShareLinkErrorCode =
  | 'PROJECT_NOT_FOUND'
  | 'LINK_NOT_FOUND'
  | 'LINK_EXPIRED'
  | 'LINK_DISABLED'
  | 'MAX_VIEWS_REACHED'
  | 'PASSWORD_REQUIRED'
  | 'INVALID_PASSWORD';

export class ShareLinkError extends Error {
  code: ShareLinkErrorCode;

  constructor(message: string, code: ShareLinkErrorCode) {
    super(message);
    this.name = 'ShareLinkError';
    this.code = code;
  }
}
